 1	import * as React from 'react';
 2	import { Chip } from '@patternfly/react-core';
 3	import { t } from 'utils/I18nUtils';
 4	
 5	interface Shortcut {
 6	  description: string;
 7	  shortcut: string;
 8	}
 9	
10	const shortcuts: Shortcut[] = [
11	  { shortcut: t('Mouse wheel'), description: t('Zoom') },
12	  { shortcut: t('Click + Drag'), description: t('Panning') },
13	  { shortcut: 'Shift + Drag', description: t('Select zoom area') },
14	  { shortcut: 'Ctrl + Drag', description: t('Select zoom area') },
15	  // { shortcut: t('Right click'), description: t('Contextual menu on nodes') },
16	  { shortcut: t('Single click'), description: t('Details in side panel on nodes') }
17	];
18	
19	const makeShortcut = (shortcut: Shortcut): React.ReactNode => {
20	  return (
21	    <div style={{ display: 'flex', marginBottom: '10px' }}>
22	      <div style={{ flex: '40%' }}>
23	        <Chip isReadOnly>{t(shortcut.shortcut)}</Chip>
24	      </div>
25	      <div style={{ flex: '60%' }}>{t(shortcut.description)}</div>
26	    </div>
27	  );
28	};
29	
30	export const MeshShortcuts = (): React.ReactNode => (
31	  <>
32	    {shortcuts.map(
33	      (s: Shortcut): React.ReactNode => {
34	        return makeShortcut(s);
35	      }
36	    )}
37	  </>
38	);

